package org.apache.beam.sdk.options;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

/** Holds the result of a validation operation, including errors and warnings. */
public class ValidationResult {
  private final List<String> errors;
  private final List<String> warnings;

  /**
   * Creates a new ValidationResult with the given errors and warnings.
   *
   * @param errors The list of validation errors.
   * @param warnings The list of validation warnings.
   */
  private ValidationResult(List<String> errors, List<String> warnings) {
    this.errors = Collections.unmodifiableList(new ArrayList<>(errors));
    this.warnings = Collections.unmodifiableList(new ArrayList<>(warnings));
  }

  /**
   * Gets the list of validation errors.
   *
   * @return An unmodifiable list of error messages.
   */
  public List<String> getErrors() {
    return errors;
  }

  /**
   * Gets the list of validation warnings.
   *
   * @return An unmodifiable list of warning messages.
   */
  public List<String> getWarnings() {
    return warnings;
  }

  /**
   * Checks if the validation was successful (no errors).
   *
   * @return true if there are no errors, false otherwise.
   */
  public boolean isValid() {
    return errors.isEmpty();
  }

  /**
   * Checks if there are any validation warnings.
   *
   * @return true if there are warnings, false otherwise.
   */
  public boolean hasWarnings() {
    return !warnings.isEmpty();
  }

  /**
   * Gets the number of errors.
   *
   * @return The count of validation errors.
   */
  public int getErrorCount() {
    return errors.size();
  }

  /**
   * Gets the number of warnings.
   *
   * @return The count of validation warnings.
   */
  public int getWarningCount() {
    return warnings.size();
  }

  @Override
  public String toString() {
    return "ValidationResult{"
        + "errors="
        + errors
        + ", warnings="
        + warnings
        + '}';
  }

  /**
   * Creates a new builder for constructing ValidationResult instances.
   *
   * @return A new Builder instance.
   */
  public static Builder builder() {
    return new Builder();
  }

  /** Builder for constructing ValidationResult instances. */
  public static class Builder {
    private final List<String> errors = new ArrayList<>();
    private final List<String> warnings = new ArrayList<>();

    /**
     * Adds an error message to the result.
     *
     * @param error The error message to add.
     * @return This builder for method chaining.
     */
    public Builder addError(String error) {
      if (error != null && !error.isEmpty()) {
        this.errors.add(error);
      }
      return this;
    }

    /**
     * Adds a warning message to the result.
     *
     * @param warning The warning message to add.
     * @return This builder for method chaining.
     */
    public Builder addWarning(String warning) {
      if (warning != null && !warning.isEmpty()) {
        this.warnings.add(warning);
      }
      return this;
    }

    /**
     * Adds multiple error messages to the result.
     *
     * @param errorList The list of error messages to add.
     * @return This builder for method chaining.
     */
    public Builder addErrors(List<String> errorList) {
      if (errorList != null) {
        errorList.stream().filter(e -> e != null && !e.isEmpty()).forEach(this.errors::add);
      }
      return this;
    }

    /**
     * Adds multiple warning messages to the result.
     *
     * @param warningList The list of warning messages to add.
     * @return This builder for method chaining.
     */
    public Builder addWarnings(List<String> warningList) {
      if (warningList != null) {
        warningList.stream().filter(w -> w != null && !w.isEmpty()).forEach(this.warnings::add);
      }
      return this;
    }

    /**
     * Builds the ValidationResult with the accumulated errors and warnings.
     *
     * @return A new ValidationResult instance.
     */
    public ValidationResult build() {
      return new ValidationResult(errors, warnings);
    }
  }
}

