package org.apache.beam.sdk.options;

import java.util.ArrayList;
import java.util.List;
import java.util.function.Predicate;

/** Validates PipelineOptions using a Builder pattern for accumulating validation rules. */
public class PipelineOptionsValidator {

  /** A validation rule that can be applied to PipelineOptions. */
  @FunctionalInterface
  public interface ValidationRule {
    /**
     * Validates the given PipelineOptions.
     *
     * @param options The options to validate.
     * @return The validation result.
     */
    ValidationResult validate(PipelineOptions options);
  }

  /** A rule that validates a required property. */
  public static class RequiredRule implements ValidationRule {
    private final String propertyName;
    private final PropertyGetter propertyGetter;

    /**
     * Creates a rule that validates a required property.
     *
     * @param propertyName The name of the property.
     * @param propertyGetter A function to get the property value.
     */
    public RequiredRule(String propertyName, PropertyGetter propertyGetter) {
      this.propertyName = propertyName;
      this.propertyGetter = propertyGetter;
    }

    @Override
    public ValidationResult validate(PipelineOptions options) {
      ValidationResult.Builder builder = ValidationResult.builder();
      Object value = propertyGetter.get(options);
      if (value == null) {
        builder.addError("Missing required value for property: " + propertyName);
      }
      return builder.build();
    }
  }

  /** A rule that validates a property's type. */
  public static class TypeRule implements ValidationRule {
    private final String propertyName;
    private final PropertyGetter propertyGetter;
    private final Class<?> expectedType;

    /**
     * Creates a rule that validates a property's type.
     *
     * @param propertyName The name of the property.
     * @param propertyGetter A function to get the property value.
     * @param expectedType The expected type of the property.
     */
    public TypeRule(String propertyName, PropertyGetter propertyGetter, Class<?> expectedType) {
      this.propertyName = propertyName;
      this.propertyGetter = propertyGetter;
      this.expectedType = expectedType;
    }

    @Override
    public ValidationResult validate(PipelineOptions options) {
      ValidationResult.Builder builder = ValidationResult.builder();
      Object value = propertyGetter.get(options);
      if (value != null && !expectedType.isInstance(value)) {
        builder.addError(
            "Invalid type for property: "
                + propertyName
                + ". Expected: "
                + expectedType.getSimpleName()
                + ", Got: "
                + value.getClass().getSimpleName());
      }
      return builder.build();
    }
  }

  /** A rule that validates a property is within a range. */
  public static class RangeRule implements ValidationRule {
    private final String propertyName;
    private final PropertyGetter propertyGetter;
    private final Comparable minValue;
    private final Comparable maxValue;

    /**
     * Creates a rule that validates a property is within a range.
     *
     * @param propertyName The name of the property.
     * @param propertyGetter A function to get the property value.
     * @param minValue The minimum allowed value (inclusive), or null for no minimum.
     * @param maxValue The maximum allowed value (inclusive), or null for no maximum.
     */
    public RangeRule(
        String propertyName,
        PropertyGetter propertyGetter,
        Comparable minValue,
        Comparable maxValue) {
      this.propertyName = propertyName;
      this.propertyGetter = propertyGetter;
      this.minValue = minValue;
      this.maxValue = maxValue;
    }

    @Override
    @SuppressWarnings("unchecked")
    public ValidationResult validate(PipelineOptions options) {
      ValidationResult.Builder builder = ValidationResult.builder();
      Object value = propertyGetter.get(options);
      if (value != null && value instanceof Comparable) {
        Comparable comparableValue = (Comparable) value;
        if (minValue != null && comparableValue.compareTo(minValue) < 0) {
          builder.addError(
              "Value for property: "
                  + propertyName
                  + " is below minimum: "
                  + minValue
                  + ". Got: "
                  + value);
        }
        if (maxValue != null && comparableValue.compareTo(maxValue) > 0) {
          builder.addError(
              "Value for property: "
                  + propertyName
                  + " is above maximum: "
                  + maxValue
                  + ". Got: "
                  + value);
        }
      }
      return builder.build();
    }
  }

  /** A rule that applies a custom predicate validation. */
  public static class PredicateRule implements ValidationRule {
    private final String propertyName;
    private final PropertyGetter propertyGetter;
    private final Predicate<Object> predicate;
    private final String errorMessage;

    /**
     * Creates a rule that applies a custom predicate validation.
     *
     * @param propertyName The name of the property.
     * @param propertyGetter A function to get the property value.
     * @param predicate A predicate that returns true if the value is valid.
     * @param errorMessage The error message if validation fails.
     */
    public PredicateRule(
        String propertyName,
        PropertyGetter propertyGetter,
        Predicate<Object> predicate,
        String errorMessage) {
      this.propertyName = propertyName;
      this.propertyGetter = propertyGetter;
      this.predicate = predicate;
      this.errorMessage = errorMessage;
    }

    @Override
    public ValidationResult validate(PipelineOptions options) {
      ValidationResult.Builder builder = ValidationResult.builder();
      Object value = propertyGetter.get(options);
      if (!predicate.test(value)) {
        builder.addError(
            errorMessage != null ? errorMessage : "Invalid value for property: " + propertyName);
      }
      return builder.build();
    }
  }

  /** Functional interface for getting property values from PipelineOptions. */
  @FunctionalInterface
  public interface PropertyGetter {
    /**
     * Gets a property value from PipelineOptions.
     *
     * @param options The options object.
     * @return The property value.
     */
    Object get(PipelineOptions options);
  }

  /** Builder for accumulating validation rules. */
  public static class Builder {
    private final List<ValidationRule> rules = new ArrayList<>();

    /**
     * Adds a validation rule that checks if a property is required (not null).
     *
     * @param propertyName The name of the property.
     * @param propertyGetter A function to get the property value.
     * @return This builder for method chaining.
     */
    public Builder validateRequired(String propertyName, PropertyGetter propertyGetter) {
      rules.add(new RequiredRule(propertyName, propertyGetter));
      return this;
    }

    /**
     * Adds a validation rule that checks if a property has the expected type.
     *
     * @param propertyName The name of the property.
     * @param propertyGetter A function to get the property value.
     * @param expectedType The expected type of the property.
     * @return This builder for method chaining.
     */
    public Builder validateType(
        String propertyName, PropertyGetter propertyGetter, Class<?> expectedType) {
      rules.add(new TypeRule(propertyName, propertyGetter, expectedType));
      return this;
    }

    /**
     * Adds a validation rule that checks if a property is within a range.
     *
     * @param propertyName The name of the property.
     * @param propertyGetter A function to get the property value.
     * @param minValue The minimum allowed value (inclusive), or null for no minimum.
     * @param maxValue The maximum allowed value (inclusive), or null for no maximum.
     * @return This builder for method chaining.
     */
    public Builder validateRange(
        String propertyName, PropertyGetter propertyGetter, Comparable minValue, Comparable maxValue) {
      rules.add(new RangeRule(propertyName, propertyGetter, minValue, maxValue));
      return this;
    }

    /**
     * Adds a custom validation rule.
     *
     * @param rule The validation rule to add.
     * @return This builder for method chaining.
     */
    public Builder addRule(ValidationRule rule) {
      rules.add(rule);
      return this;
    }

    /**
     * Adds a custom validation rule using a predicate.
     *
     * @param propertyName The name of the property.
     * @param propertyGetter A function to get the property value.
     * @param predicate A predicate that returns true if the value is valid.
     * @param errorMessage The error message if validation fails.
     * @return This builder for method chaining.
     */
    public Builder validateWithPredicate(
        String propertyName,
        PropertyGetter propertyGetter,
        Predicate<Object> predicate,
        String errorMessage) {
      rules.add(new PredicateRule(propertyName, propertyGetter, predicate, errorMessage));
      return this;
    }

    /**
     * Validates the given PipelineOptions with all accumulated rules.
     *
     * @param options The options to validate.
     * @return The validation result.
     */
    public ValidationResult validate(PipelineOptions options) {
      ValidationResult.Builder resultBuilder = ValidationResult.builder();
      for (ValidationRule rule : rules) {
        ValidationResult ruleResult = rule.validate(options);
        resultBuilder.addErrors(ruleResult.getErrors());
        resultBuilder.addWarnings(ruleResult.getWarnings());
      }
      return resultBuilder.build();
    }
  }

  /**
   * Creates a new builder for constructing a validator.
   *
   * @return A new Builder instance.
   */
  public static Builder builder() {
    return new Builder();
  }
}

