package org.apache.beam.sdk.options;

import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertFalse;
import static org.junit.Assert.assertTrue;

import org.junit.Test;
import org.junit.runner.RunWith;
import org.junit.runners.JUnit4;

/** Tests for {@link PipelineOptionsValidator}. */
@RunWith(JUnit4.class)
public class PipelineOptionsValidatorTest {

  /** A minimal test options class. */
  public static class TestOptions implements PipelineOptions {
    private String requiredField;
    private String optionalField;
    private Integer numericField;
    private String stringField;

    public String getRequiredField() {
      return requiredField;
    }

    public void setRequiredField(String value) {
      this.requiredField = value;
    }

    public String getOptionalField() {
      return optionalField;
    }

    public void setOptionalField(String value) {
      this.optionalField = value;
    }

    public Integer getNumericField() {
      return numericField;
    }

    public void setNumericField(Integer value) {
      this.numericField = value;
    }

    public String getStringField() {
      return stringField;
    }

    public void setStringField(String value) {
      this.stringField = value;
    }
  }

  @Test
  public void testValidateRequired_Success() {
    TestOptions options = new TestOptions();
    options.setRequiredField("value");

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRequired("requiredField", o -> ((TestOptions) o).getRequiredField())
            .validate(options);

    assertTrue("Validation should pass when required field is set", result.isValid());
    assertEquals("Should have no errors", 0, result.getErrorCount());
  }

  @Test
  public void testValidateRequired_Failure() {
    TestOptions options = new TestOptions();
    options.setRequiredField(null);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRequired("requiredField", o -> ((TestOptions) o).getRequiredField())
            .validate(options);

    assertFalse("Validation should fail when required field is null", result.isValid());
    assertEquals("Should have 1 error", 1, result.getErrorCount());
    assertTrue("Error message should contain property name",
        result.getErrors().get(0).contains("requiredField"));
  }

  @Test
  public void testValidateType_Success() {
    TestOptions options = new TestOptions();
    options.setStringField("test");

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateType("stringField", o -> ((TestOptions) o).getStringField(), String.class)
            .validate(options);

    assertTrue("Validation should pass for correct type", result.isValid());
  }

  @Test
  public void testValidateType_Failure() {
    TestOptions options = new TestOptions();
    options.setNumericField(42);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateType("numericField", o -> ((TestOptions) o).getNumericField(), String.class)
            .validate(options);

    assertFalse("Validation should fail for incorrect type", result.isValid());
    assertEquals("Should have 1 error", 1, result.getErrorCount());
  }

  @Test
  public void testValidateRange_MinMaxSuccess() {
    TestOptions options = new TestOptions();
    options.setNumericField(50);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRange("numericField", o -> ((TestOptions) o).getNumericField(), 0, 100)
            .validate(options);

    assertTrue("Validation should pass when value is within range", result.isValid());
  }

  @Test
  public void testValidateRange_BelowMin() {
    TestOptions options = new TestOptions();
    options.setNumericField(-10);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRange("numericField", o -> ((TestOptions) o).getNumericField(), 0, 100)
            .validate(options);

    assertFalse("Validation should fail when value is below min", result.isValid());
    assertEquals("Should have 1 error", 1, result.getErrorCount());
    assertTrue("Error should mention minimum", result.getErrors().get(0).contains("minimum"));
  }

  @Test
  public void testValidateRange_AboveMax() {
    TestOptions options = new TestOptions();
    options.setNumericField(150);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRange("numericField", o -> ((TestOptions) o).getNumericField(), 0, 100)
            .validate(options);

    assertFalse("Validation should fail when value is above max", result.isValid());
    assertEquals("Should have 1 error", 1, result.getErrorCount());
    assertTrue("Error should mention maximum", result.getErrors().get(0).contains("maximum"));
  }

  @Test
  public void testMultipleRules() {
    TestOptions options = new TestOptions();
    options.setRequiredField("value");
    options.setNumericField(50);
    options.setStringField("test");

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRequired("requiredField", o -> ((TestOptions) o).getRequiredField())
            .validateType("stringField", o -> ((TestOptions) o).getStringField(), String.class)
            .validateRange("numericField", o -> ((TestOptions) o).getNumericField(), 0, 100)
            .validate(options);

    assertTrue("All validations should pass", result.isValid());
    assertEquals("Should have no errors", 0, result.getErrorCount());
  }

  @Test
  public void testMultipleRules_WithFailures() {
    TestOptions options = new TestOptions();
    options.setRequiredField(null);
    options.setNumericField(150);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRequired("requiredField", o -> ((TestOptions) o).getRequiredField())
            .validateRange("numericField", o -> ((TestOptions) o).getNumericField(), 0, 100)
            .validate(options);

    assertFalse("Should have validation failures", result.isValid());
    assertEquals("Should have 2 errors", 2, result.getErrorCount());
  }

  @Test
  public void testValidationResult_IsValid() {
    ValidationResult result = ValidationResult.builder().build();
    assertTrue("Empty result should be valid", result.isValid());
  }

  @Test
  public void testValidationResult_WithErrors() {
    ValidationResult result =
        ValidationResult.builder()
            .addError("Error 1")
            .addError("Error 2")
            .build();

    assertFalse("Result with errors should be invalid", result.isValid());
    assertEquals("Should have 2 errors", 2, result.getErrorCount());
    assertEquals("Should have 0 warnings", 0, result.getWarningCount());
  }

  @Test
  public void testValidationResult_WithWarnings() {
    ValidationResult result =
        ValidationResult.builder()
            .addWarning("Warning 1")
            .addWarning("Warning 2")
            .build();

    assertTrue("Result with only warnings should be valid", result.isValid());
    assertEquals("Should have 0 errors", 0, result.getErrorCount());
    assertEquals("Should have 2 warnings", 2, result.getWarningCount());
    assertTrue("Should have warnings", result.hasWarnings());
  }

  @Test
  public void testBuilderChaining() {
    TestOptions options = new TestOptions();
    options.setRequiredField("required");
    options.setNumericField(50);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRequired("requiredField", o -> ((TestOptions) o).getRequiredField())
            .validateRange("numericField", o -> ((TestOptions) o).getNumericField(), 0, 100)
            .validate(options);

    assertTrue("Chained builder should work correctly", result.isValid());
  }

  @Test
  public void testCustomPredicate() {
    TestOptions options = new TestOptions();
    options.setNumericField(42);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateWithPredicate(
                "numericField",
                o -> ((TestOptions) o).getNumericField(),
                v -> v instanceof Integer && (Integer) v > 0,
                "Numeric field must be a positive integer")
            .validate(options);

    assertTrue("Custom predicate validation should pass", result.isValid());
  }

  @Test
  public void testCustomPredicate_Failure() {
    TestOptions options = new TestOptions();
    options.setNumericField(-5);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateWithPredicate(
                "numericField",
                o -> ((TestOptions) o).getNumericField(),
                v -> v instanceof Integer && (Integer) v > 0,
                "Numeric field must be a positive integer")
            .validate(options);

    assertFalse("Custom predicate validation should fail", result.isValid());
    assertEquals("Should have 1 error", 1, result.getErrorCount());
    assertTrue("Error should use custom message",
        result.getErrors().get(0).contains("positive integer"));
  }
}

# PipelineOptionsValidator Usage Guide

## Quick Start

### Basic Validation
```java
// Create PipelineOptions
MyPipelineOptions options = PipelineOptionsFactory.as(MyPipelineOptions.class);
options.setName("my-job");
options.setThreadCount(4);

// Validate using builder
ValidationResult result = PipelineOptionsValidator.builder()
    .validateRequired("name", opts -> opts.getName())
    .validateRange("threadCount", opts -> opts.getThreadCount(), 1, 32)
    .validate(options);

// Check results
if (result.isValid()) {
    System.out.println("All validations passed!");
} else {
    result.getErrors().forEach(error -> System.err.println(error));
}
```

## Validation Methods

### 1. validateRequired()
Validates that a property is not null.

```java
builder.validateRequired("propertyName", options -> options.getPropertyValue())
```

**Example:**
```java
builder.validateRequired("name", opts -> opts.getName())
```

### 2. validateType()
Validates that a property has the expected type.

```java
builder.validateType("propertyName", options -> options.getPropertyValue(), String.class)
```

**Example:**
```java
builder.validateType("name", opts -> opts.getName(), String.class)
builder.validateType("count", opts -> opts.getCount(), Integer.class)
```

### 3. validateRange()
Validates that a comparable value is within a range (inclusive).

```java
builder.validateRange("propertyName", options -> options.getPropertyValue(), minValue, maxValue)
```

**Examples:**
```java
// Integer range
builder.validateRange("threadCount", opts -> opts.getThreadCount(), 1, 32)

// Double range
builder.validateRange("timeout", opts -> opts.getTimeout(), 0.1, 60.0)

// Only minimum
builder.validateRange("age", opts -> opts.getAge(), 18, null)

// Only maximum
builder.validateRange("percentage", opts -> opts.getPercentage(), null, 100)
```

### 4. validateWithPredicate()
Validates using a custom predicate function.

```java
builder.validateWithPredicate(
    "propertyName",
    options -> options.getPropertyValue(),
    predicate,           // Returns true if valid
    "Error message"      // Error if predicate is false
)
```

**Examples:**
```java
// Email validation
builder.validateWithPredicate(
    "email",
    opts -> opts.getEmail(),
    email -> email instanceof String && email.toString().matches("^[A-Za-z0-9+_.-]+@(.+)$"),
    "Invalid email format"
)

// Positive number
builder.validateWithPredicate(
    "count",
    opts -> opts.getCount(),
    v -> v instanceof Integer && (Integer) v > 0,
    "Count must be positive"
)

// Non-empty string
builder.validateWithPredicate(
    "name",
    opts -> opts.getName(),
    v -> v instanceof String && !((String) v).isEmpty(),
    "Name cannot be empty"
)
```

## Advanced Usage

### Custom Validation Rules
```java
// Implement custom rule
PipelineOptionsValidator.ValidationRule customRule =
    options -> {
        ValidationResult.Builder resultBuilder = ValidationResult.builder();
        if (/* some condition */) {
            resultBuilder.addError("Custom validation failed");
        }
        return resultBuilder.build();
    };

// Add to validator
builder.addRule(customRule)
```

### Multiple Rules
```java
ValidationResult result = PipelineOptionsValidator.builder()
    .validateRequired("name", opts -> opts.getName())
    .validateRequired("output", opts -> opts.getOutput())
    .validateRange("workers", opts -> opts.getWorkers(), 1, 100)
    .validateType("timeout", opts -> opts.getTimeout(), Integer.class)
    .validate(options);
```

### Method Chaining
```java
ValidationResult result = PipelineOptionsValidator.builder()
    .validateRequired("field1", opts -> opts.getField1())
    .validateRequired("field2", opts -> opts.getField2())
    .validateRequired("field3", opts -> opts.getField3())
    .validate(options);
```

## ValidationResult

### Check Validity
```java
if (result.isValid()) {
    // Proceed with execution
}
```

### Access Errors
```java
List<String> errors = result.getErrors();
int errorCount = result.getErrorCount();

for (String error : errors) {
    System.err.println("Error: " + error);
}
```

### Access Warnings
```java
if (result.hasWarnings()) {
    List<String> warnings = result.getWarnings();
    int warningCount = result.getWarningCount();
    // Handle warnings
}
```

### Add Errors/Warnings in Custom Rules
```java
ValidationResult.Builder resultBuilder = ValidationResult.builder();

resultBuilder.addError("Something is wrong");
resultBuilder.addWarning("Something might be wrong");
resultBuilder.addErrors(Arrays.asList("Error 1", "Error 2"));
resultBuilder.addWarnings(Arrays.asList("Warning 1", "Warning 2"));

ValidationResult result = resultBuilder.build();
```

## Real-World Example

```java
public class PipelineRunner {
    public static void main(String[] args) {
        // Parse options from command line
        DataflowPipelineOptions options =
            PipelineOptionsFactory.fromArgs(args)
                .withValidation()
                .as(DataflowPipelineOptions.class);

        // Validate using new validator
        ValidationResult result = PipelineOptionsValidator.builder()
            // Required fields
            .validateRequired("project", opts -> opts.getProject())
            .validateRequired("runner", opts -> opts.getRunner())

            // Type validations
            .validateType("project", opts -> opts.getProject(), String.class)
            .validateType("maxNumWorkers", opts -> opts.getMaxNumWorkers(), Integer.class)

            // Range validations
            .validateRange("maxNumWorkers",
                opts -> opts.getMaxNumWorkers(),
                1, 1000)

            // Custom validations
            .validateWithPredicate(
                "project",
                opts -> opts.getProject(),
                project -> !((String) project).isEmpty(),
                "Project name cannot be empty")

            .validate(options);

        // Handle validation results
        if (!result.isValid()) {
            System.err.println("Validation failed:");
            result.getErrors().forEach(e -> System.err.println("  - " + e));
            System.exit(1);
        }

        if (result.hasWarnings()) {
            System.out.println("Validation warnings:");
            result.getWarnings().forEach(w -> System.out.println("  - " + w));
        }

        // Create and run pipeline
        Pipeline p = Pipeline.create(options);
        // ... pipeline logic ...
        p.run().waitUntilFinish();
    }
}
```

## Best Practices

1. **Validate Early**: Run validation immediately after creating/parsing options
2. **Clear Error Messages**: Use descriptive error messages for debugging
3. **Fail Fast**: Check `isValid()` before proceeding
4. **Group Related Rules**: Keep validation rules organized logically
5. **Use Predicates for Complex Logic**: Don't try to fit complex validation in required/type/range checks
6. **Document Validation Rules**: Comment why certain validations exist
7. **Test Validation**: Write unit tests for custom validation rules

## Common Patterns

### Conditional Validation
```java
builder.validateWithPredicate(
    "parallelism",
    opts -> opts.getParallelism(),
    v -> {
        // Only required if using DataflowRunner
        if ("DataflowRunner".equals(opts.getRunner())) {
            return v != null && (Integer) v > 0;
        }
        return true;
    },
    "Parallelism required for DataflowRunner"
)
```

### Cross-Field Validation
```java
PipelineOptionsValidator.ValidationRule crossFieldRule = options -> {
    ValidationResult.Builder builder = ValidationResult.builder();
    String startTime = options.getStartTime();
    String endTime = options.getEndTime();

    if (startTime != null && endTime != null) {
        if (startTime.compareTo(endTime) >= 0) {
            builder.addError("Start time must be before end time");
        }
    }

    return builder.build();
};

PipelineOptionsValidator.builder()
    .addRule(crossFieldRule)
    .validate(options);
```

