package org.apache.beam.sdk.options;

import java.util.ArrayList;
import java.util.List;
import java.util.function.Predicate;

/** Validates PipelineOptions using a Builder pattern for accumulating validation rules. */
public class PipelineOptionsValidator {

  /** A validation rule that can be applied to PipelineOptions. */
  @FunctionalInterface
  public interface ValidationRule {
    /**
     * Validates the given PipelineOptions.
     *
     * @param options The options to validate.
     * @return The validation result.
     */
    ValidationResult validate(PipelineOptions options);
  }

  /** A rule that validates a required property. */
  public static class RequiredRule implements ValidationRule {
    private final String propertyName;
    private final PropertyGetter propertyGetter;

    /**
     * Creates a rule that validates a required property.
     *
     * @param propertyName The name of the property.
     * @param propertyGetter A function to get the property value.
     */
    public RequiredRule(String propertyName, PropertyGetter propertyGetter) {
      this.propertyName = propertyName;
      this.propertyGetter = propertyGetter;
    }

    @Override
    public ValidationResult validate(PipelineOptions options) {
      ValidationResult.Builder builder = ValidationResult.builder();
      Object value = propertyGetter.get(options);
      if (value == null) {
        builder.addError("Missing required value for property: " + propertyName);
      }
      return builder.build();
    }
  }

  /** A rule that validates a property's type. */
  public static class TypeRule implements ValidationRule {
    private final String propertyName;
    private final PropertyGetter propertyGetter;
    private final Class<?> expectedType;

    /**
     * Creates a rule that validates a property's type.
     *
     * @param propertyName The name of the property.
     * @param propertyGetter A function to get the property value.
     * @param expectedType The expected type of the property.
     */
    public TypeRule(String propertyName, PropertyGetter propertyGetter, Class<?> expectedType) {
      this.propertyName = propertyName;
      this.propertyGetter = propertyGetter;
      this.expectedType = expectedType;
    }

    @Override
    public ValidationResult validate(PipelineOptions options) {
      ValidationResult.Builder builder = ValidationResult.builder();
      Object value = propertyGetter.get(options);
